import{_ as a,o,c as i,a2 as r}from"./chunks/framework.HMsj64NP.js";const m=JSON.parse('{"title":"Pico C/C++ SDK","description":"","frontmatter":{},"headers":[],"relativePath":"examples/index.md","filePath":"examples/index.md"}'),t={name:"examples/index.md"};function d(n,e,l,s,c,p){return o(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="pico-c-c-sdk" tabindex="-1">Pico C/C++ SDK <a class="header-anchor" href="#pico-c-c-sdk" aria-label="Permalink to &quot;Pico C/C++ SDK&quot;">​</a></h1><p>Esta seccion es el nucleo del curso: el manejo del <strong>RP2040</strong> (Raspberry Pi Pico) directamente con las funciones oficiales del <strong>Pico SDK 2.2.0</strong>, sin pasar por Arduino. Se divide en dos rutas complementarias:</p><ul><li><strong>Periféricos Básicos</strong> — 12 practicas secuenciales, cada una limitada a un solo periferico: inicializacion, asignacion de pines, configuracion elemental y un ciclo de validacion basico.</li><li><strong>Aplicaciones e Integración</strong> — proyectos que combinan varios perifericos entre si (y, en algunos casos, hardware o bibliotecas de terceros) para resolver un problema completo.</li></ul><h2 id="perifericos-basicos" tabindex="-1">Periféricos Básicos <a class="header-anchor" href="#perifericos-basicos" aria-label="Permalink to &quot;Periféricos Básicos&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Práctica</th><th>Contenido</th></tr></thead><tbody><tr><td>1</td><td><a href="./../examples/basic/00_blink">Blink</a></td><td><code>gpio_init</code>, <code>gpio_put</code>, <code>sleep_ms</code>, CMake basico</td></tr><tr><td>2</td><td><a href="./../examples/basic/01_stdio">Serial</a></td><td><code>stdio_init_all</code> + <code>printf</code> por USB</td></tr><tr><td>3</td><td><a href="./../examples/basic/02_gpio">GPIO</a></td><td>Entrada de boton, pull-up interno, antirrebote por <em>polling</em></td></tr><tr><td>4</td><td><a href="./../examples/basic/03_irq">IRQ</a></td><td>Interrupciones externas, flancos, callbacks</td></tr><tr><td>5</td><td><a href="./../examples/basic/04_adc">ADC</a></td><td>Conversion analogica, sensor de temperatura interno (canal 4)</td></tr><tr><td>6</td><td><a href="./../examples/basic/05_pwm">PWM</a></td><td>Slices, ciclo de trabajo, divisores de reloj</td></tr><tr><td>7</td><td><a href="./../examples/basic/06_timer">Timer</a></td><td><code>repeating_timer</code>, alarmas asincronas no bloqueantes</td></tr><tr><td>8</td><td><a href="./../examples/basic/07_uart">UART</a></td><td>Baudrate, TX/RX, eco real contra el CH340 del shield</td></tr><tr><td>9</td><td><a href="./../examples/basic/08_i2c">I2C</a></td><td>Escaner de bus (sin OLED, diferido a Aplicaciones)</td></tr><tr><td>10</td><td><a href="./../examples/basic/09_spi">SPI</a></td><td>Verificacion de <code>CHIP_ID</code> del BMI270 real, sin biblioteca</td></tr><tr><td>11</td><td><a href="./../examples/basic/10_multicore">Multicore</a></td><td>Core 1, FIFOs entre nucleos</td></tr><tr><td>12</td><td><a href="./../examples/basic/11_pio">PIO</a></td><td>Maquinas de estado, ensamblador <code>.pio</code> basico</td></tr></tbody></table><h3 id="herramientas-de-desarrollo" tabindex="-1">Herramientas de Desarrollo <a class="header-anchor" href="#herramientas-de-desarrollo" aria-label="Permalink to &quot;Herramientas de Desarrollo&quot;">​</a></h3><ul><li>SDK de RP2040</li><li>Compiladores y depuradores</li><li>Herramientas de programación y carga</li></ul><h2 id="practicas-de-laboratorio" tabindex="-1">Prácticas de Laboratorio <a class="header-anchor" href="#practicas-de-laboratorio" aria-label="Permalink to &quot;Prácticas de Laboratorio&quot;">​</a></h2><h2 id="aplicaciones-e-integracion" tabindex="-1">Aplicaciones e Integración <a class="header-anchor" href="#aplicaciones-e-integracion" aria-label="Permalink to &quot;Aplicaciones e Integración&quot;">​</a></h2><p>Proyectos completos que integran varios de los perifericos anteriores con hardware real del shield (sensores externos, display, IMU) o funcionalidad avanzada del RP2040 (DMA).</p><h3 id="_1-sensor-de-temperatura-interno-con-despliegue-en-oled" tabindex="-1">1. <a href="./01_OledTempInt">Sensor de Temperatura Interno con Despliegue en OLED</a> <a class="header-anchor" href="#_1-sensor-de-temperatura-interno-con-despliegue-en-oled" aria-label="Permalink to &quot;1. [Sensor de Temperatura Interno con Despliegue en OLED](./01_OledTempInt.md)&quot;">​</a></h3><p>Lectura del sensor de temperatura interno por ADC, con despliegue del valor en un display OLED SSD1306 via I2C (biblioteca <code>pico-ssd1306</code> de David Schramm). Primera integracion ADC + I2C de la seccion.</p><h3 id="_2-control-de-brillo-de-un-led-mediante-potenciometro-adc-pwm-oled" tabindex="-1">2. <a href="./02_adcpwm">Control de Brillo de un LED mediante Potenciometro (ADC + PWM + OLED)</a> <a class="header-anchor" href="#_2-control-de-brillo-de-un-led-mediante-potenciometro-adc-pwm-oled" aria-label="Permalink to &quot;2. [Control de Brillo de un LED mediante Potenciometro (ADC + PWM + OLED)](./02_adcpwm.md)&quot;">​</a></h3><p>Un potenciometro externo, leido por el ADC, controla en tiempo real el ciclo de trabajo de una senal PWM que modula el brillo de un LED. El valor crudo, el porcentaje y el voltaje estimado se muestran de forma simultanea en el OLED, con una tasa de refresco desacoplada de la del par ADC-PWM.</p><h3 id="_3-imu-bmi270-por-spi-con-despliegue-en-oled" tabindex="-1">3. <a href="./03_oledbmi270">IMU BMI270 por SPI con Despliegue en OLED</a> <a class="header-anchor" href="#_3-imu-bmi270-por-spi-con-despliegue-en-oled" aria-label="Permalink to &quot;3. [IMU BMI270 por SPI con Despliegue en OLED](./03_oledbmi270.md)&quot;">​</a></h3><p>Inicializacion completa del BMI270 (secuencia oficial de Bosch, incluida la carga del archivo de configuracion de 8192 bytes) y lectura de acelerometro y giroscopio por SPI, con los valores en las tres unidades desplegados en el OLED y por consola serial.</p><h3 id="_4-osciloscopio-oled-de-un-canal" tabindex="-1">4. <a href="./04_osciloscope">Osciloscopio OLED de un Canal</a> <a class="header-anchor" href="#_4-osciloscopio-oled-de-un-canal" aria-label="Permalink to &quot;4. [Osciloscopio OLED de un Canal](./04_osciloscope.md)&quot;">​</a></h3><p>Captura de una senal analogica externa mediante ADC y DMA en modo de bloque, con disparo (<em>trigger</em>) por histeresis de dos niveles y autoescala vertical, dibujando el trazo resultante en el OLED — el equivalente funcional, en miniatura, de un osciloscopio de banco.</p><h2 id="flujo-recomendado" tabindex="-1">Flujo Recomendado <a class="header-anchor" href="#flujo-recomendado" aria-label="Permalink to &quot;Flujo Recomendado&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">picodev-flash</span></span></code></pre></div>',20)])])}const h=a(t,[["render",d]]);export{m as __pageData,h as default};
